prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?task ?taskName ?taskId ?taskLoopType WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1c273a0818b146269ac04f6b8d518698" ;
         bbo:name ?modelName .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName ;
        bbo:id ?taskId .
  OPTIONAL { ?task bboExt:loopType ?taskLoopType . }
  ?choreo a bboExt:Choreography .
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idProp ?idVal WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         ?idProp ?idVal .
  VALUES ?idProp { tai:normalizedId tai:originalId }
  FILTER(STR(?idVal) = "1c273a0818b146269ac04f6b8d518698")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task ?taskName ?taskId ?loopType ?choreoName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1c273a0818b146269ac04f6b8d518698" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  OPTIONAL { ?task bboExt:loopType ?loopType . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
ORDER BY ?choreoName ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task ?taskName ?taskId ?loopType ?defs
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1c273a0818b146269ac04f6b8d518698" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .

  ?task bbo:name ?taskName .
  OPTIONAL { ?task bbo:id ?taskId . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}
ORDER BY ?taskName
LIMIT 25
